INSERT INTO public."AgendaItems"
  ("MeetingID","Title","Description","ItemNumber","OrderNumber","FileNumber")
SELECT
  (SELECT mid FROM m),
  s.title,
  s.description,
  s.item_number,
  s.item_number,   
  s.file_number
FROM src s;

