-- Insert chunks for Sep 12, 2025
WITH m AS (
  SELECT "MeetingID" AS mid FROM public."Meetings" WHERE "Date" = '2025-09-12'
),
src AS (
  SELECT
    (j->>'ChunkNum')::integer                        AS ChunkNum,
    (j->>'StartTime')::float                         AS StartTime,
    (j->>'EndTime')::float                           AS EndTime,
    j->>'Content'                           AS Content,
    (j->>'Embedding')::vector                         AS Embedding
  FROM jsonb_array_elements(
    $$ 
